import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.xml.ws.BindingType;
import javax.xml.ws.soap.SOAPBinding;
import javax.xml.ws.soap.MTOM;
import javax.xml.ws.handler.MessageContext;
import javax.xml.soap.SOAPMessage;
import javax.xml.soap.SOAPHeader;
import javax.xml.soap.SOAPElement;
import javax.xml.namespace.QName;
import java.util.Date;
import java.util.Map;
import java.util.GregorianCalendar;
import java.text.SimpleDateFormat;
import java.util.TimeZone;

@WebService
@BindingType(SOAPBinding.SOAP11HTTP_MTOM)
@MTOM
public class PaymentGatewayService {
    
    private static final long TIMESTAMP_TOLERANCE = 300000; // 5 minutes
    
    @WebMethod
    public PaymentResponse processPayment(PaymentRequest request) {
        try {
            // Validate timestamp
            validateTimestamp();
            
            // Process payment
            PaymentResponse response = new PaymentResponse();
            response.setTransactionId(generateTransactionId());
            response.setStatus("SUCCESS");
            response.setAmount(request.getAmount());
            response.setCurrency(request.getCurrency());
            
            return response;
            
        } catch (Exception e) {
            PaymentResponse response = new PaymentResponse();
            response.setStatus("FAILED");
            response.setErrorMessage(e.getMessage());
            return response;
        }
    }
    
    private void validateTimestamp() throws Exception {
        MessageContext context = MessageContext.getCurrentContext();
        Map<String, Object> requestHeaders = (Map<String, Object>) context.get(MessageContext.HTTP_REQUEST_HEADERS);
        
        SOAPMessage soapMessage = context.getMessage();
        SOAPHeader header = soapMessage.getSOAPHeader();
        
        if (header == null) {
            throw new Exception("Missing SOAP header");
        }
        
        // Extract timestamp from security header
        String timestampValue = extractTimestampFromHeader(header);
        if (timestampValue == null) {
            throw new Exception("Missing timestamp in security header");
        }
        
        // Validate timestamp
        validateTimestampValue(timestampValue);
    }
    
    private String extractTimestampFromHeader(SOAPHeader header) throws Exception {
        SOAPElement securityElement = (SOAPElement) header.getElementsByTagNameNS(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd", 
            "Security").item(0);
            
        if (securityElement == null) {
            return null;
        }
        
        SOAPElement timestampElement = (SOAPElement) securityElement.getElementsByTagNameNS(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", 
            "Timestamp").item(0);
            
        if (timestampElement == null) {
            return null;
        }
        
        SOAPElement createdElement = (SOAPElement) timestampElement.getElementsByTagNameNS(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", 
            "Created").item(0);
            
        if (createdElement != null) {
            return createdElement.getTextContent();
        }
        
        return null;
    }
    
    private void validateTimestampValue(String timestampValue) throws Exception {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
        
        Date timestamp = sdf.parse(timestampValue);
        Date now = new Date();
        
        long diff = Math.abs(now.getTime() - timestamp.getTime());
        
        if (diff > TIMESTAMP_TOLERANCE) {
            throw new Exception("Timestamp validation failed: Message may be replayed");
        }
    }
    
    private String generateTransactionId() {
        return "TXN" + System.currentTimeMillis();
    }
}

